import json
from pathlib import Path
from dataclasses import dataclass, field
from typing import Optional

@dataclass
class RiskEntry:
    risk_id: str
    taxonomy_id: str
    title: str
    description: str
    likelihood: int  # 1-5
    impact: int      # 1-5
    risk_owner: str
    treatment_strategy: str  # Accept | Mitigate | Transfer | Avoid
    status: str
    controls: list[dict] = field(default_factory=list)
    treatment_actions: list[str] = field(default_factory=list)
    review_date: Optional[str] = None

    @property
    def inherent_score(self) -> int:
        return self.likelihood * self.impact

    @property
    def control_effectiveness(self) -> float:
        if not self.controls:
            return 0
        return sum(c.get('effectiveness', 0) for c in self.controls) / len(self.controls)

    @property
    def residual_score(self) -> float:
        reduction = self.control_effectiveness / 5.0
        return round(self.inherent_score * (1 - reduction * 0.6), 1)

    @property
    def severity_band(self) -> str:
        s = self.residual_score
        if s >= 16: return 'Critical'
        if s >= 9:  return 'High'
        if s >= 4:  return 'Medium'
        return 'Low'


def load_register(path: str) -> list[RiskEntry]:
    data = json.loads(Path(path).read_text())
    return [RiskEntry(**entry) for entry in data['risks']]


def report_critical(register: list[RiskEntry]) -> None:
    critical = [r for r in register if r.severity_band in ('Critical', 'High')]
    print(f'Critical/High risks: {len(critical)}')
    for r in sorted(critical, key=lambda x: -x.residual_score):
        print(f'  [{r.risk_id}] {r.title}')
        print(f'    Residual: {r.residual_score} ({r.severity_band})')
        print(f'    Owner: {r.risk_owner} | Status: {r.status}')


if __name__ == '__main__':
    register = load_register('risk_register.json')
    report_critical(register)
